    id: 'A05',
    label: 'Search and facets',
    deterministic: true,
    verify() { return true; },
    search(items, query) { const needle = String(query).toLowerCase(); return items.filter((item) => item.name.toLowerCase().includes(needle)); }
  };
})(globalThis);

